import React, { useState, useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import AWS from 'aws-sdk';
import crypto from 'crypto-js';
import { AuthContext } from '../context/AuthContext'; // Import the context
import './css/Signin.css';

const REGION = 'us-east-1';
const CLIENT_ID = '47vhldiqfeehdt0gtavkn9a64v';
const CLIENT_SECRET = 'nn51uvndlfasq6r9gba8oil7pa97o8scdvi8r723vkt920ujgbm';

AWS.config.update({ region: REGION });

function calculateSecretHash(username, clientId, clientSecret) {
  return crypto
    .HmacSHA256(username + clientId, clientSecret)
    .toString(crypto.enc.Base64);
}

export default function Signin() {
  const { setIsAuthenticated } = useContext(AuthContext); // Access context
  const [formData, setFormData] = useState({ username: '', password: '' });
  const [errors, setErrors] = useState({});
  const [message, setMessage] = useState('');
  const navigate = useNavigate();

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  const handleSignin = async (e) => {
    e.preventDefault();

    const newErrors = {};

    // Basic validation for username and password
    if (!formData.username) newErrors.username = 'Username is required.';
    if (!formData.password) newErrors.password = 'Password is required.';
    
    // If there are errors, set them and stop further processing
    if (Object.keys(newErrors).length > 0) {
      setErrors(newErrors);
      return;
    }

    const cognito = new AWS.CognitoIdentityServiceProvider();
    const secretHash = calculateSecretHash(formData.username, CLIENT_ID, CLIENT_SECRET);

    const params = {
      AuthFlow: 'USER_PASSWORD_AUTH',
      ClientId: CLIENT_ID,
      AuthParameters: {
        USERNAME: formData.username,
        PASSWORD: formData.password,
        SECRET_HASH: secretHash,
      },
    };

    try {
      const response = await cognito.initiateAuth(params).promise();
      setMessage('Sign-in successful!');
      setIsAuthenticated(true); // Update the authentication state
      navigate('/'); // Redirect to home page after successful login
    } catch (error) {
      let errorMessage = error.message;

      // Handle specific error cases
      if (error.code === 'NotAuthorizedException') {
        errorMessage = 'Invalid username or password. Please try again.';
        newErrors.password = errorMessage; // Show the error only under the password field
      } else if (error.code === 'UserNotFoundException') {
        errorMessage = 'User not found. Please check your username.';
        newErrors.username = errorMessage;
      } else {
        errorMessage = `Error signing in: ${error.message}`;
      }

      setErrors(newErrors);
      // setMessage(errorMessage);
    }
  };

  return (
    <div className="signup-container">
      {/* Left Side: Image and Design */}
      <div className="left-container">
        <img
          src="image_url_here" // Replace with your image URL
          alt=""
          className="left-image"
        />
      </div>

      {/* Right Side: Signup Form */}
      <div className="right-container">
        <div className="signup-box">
          <h1 className="logo">
            <img src="\img\logo-200-62.png" alt="Bootstrap" />
          </h1>
          <p className="subtext">
            <h2>Welcome back to the <br />Recipe Community</h2>
          </p>

          {/* Sign-in Form */}
          <form className="signup-form" onSubmit={handleSignin}>
            <div className="input-group">
              <label>Username</label>
              <input
                type="text"
                name="username"
                value={formData.username}
                placeholder="johndadev"
                onChange={handleChange}
                required
              />
              {errors.username && <span className="error-message">{errors.username}</span>}
            </div>

            <div className="input-group">
              <label>Password</label>
              <input
                type="password"
                name="password"
                value={formData.password}
                placeholder="*************"
                onChange={handleChange}
                required
              />
              {errors.password && <span className="error-message">{errors.password}</span>}
            </div>

            <div className="terms-group">
              <input type="checkbox" id="terms" />
              <label htmlFor="terms">Remember me</label>
            </div>

            <button type="submit" className="signup-btn">
              LOG IN
            </button>
          </form>

          {/* Display success/error message */}
          {message && <p>{message}</p>}

          <p className="login-link">
            No Account yet? <a href="/Signup">SIGN UP</a>
          </p>
        </div>
      </div>
    </div>
  );
}
