// import React from "react";

import "./css/ContestRecipe.css";
import React, { useEffect, useState } from 'react';
const ContestRecipe = () => {
  const [data, setData] = useState(null);
  const [error, setError] = useState(null);
  //const apiUrl = process.env.REACT_APP_API_getRecipe;
  const apiUrl = "/get_recipe";
  //const apiUrl = "http://rr-alb-769405477.eu-west-2.elb.amazonaws.com/get_recipe";
  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await fetch(`${apiUrl}`);
        //console.log("Hello");
        // console.log(apiUrl);
        if (!response.ok) {
          throw new Error('Failed to fetch data');
          
        }
        const result = await response.json();
        setData(result);
      } catch (err) {
        setError(err.message);
      }
    };
    fetchData();
  }, [apiUrl]);
  if (error) return <p className="error-message">Error: {error}</p>;
  if (!data) return <p className="error-message">Loading...</p>;

  const toTitleCase = (str) =>
    str
      .split(' ')
      .map(word => word.charAt(0).toUpperCase() + word.slice(1))
      .join(' ');

  return (
    <div className="recipe-container">
      {/* <div>
        <h1>API Data</h1>
        <pre>{JSON.stringify(data, null, 2)}</pre>
      </div> */}
      <h1 className="page-title">Contestants' Recipes</h1>
      {/* First Recipe */}
      {data.map((dataObj, index) => {
          return (
            <div className="contestrecipe-card-upper">
  <div
    style={{
      display: 'flex',
      gap: '2%',
      alignItems: 'stretch', // Ensures all columns are equal height
      padding: '1rem',     
      borderRadius: '8px',
      boxShadow: '0 2px 8px rgba(0,0,0,0.2)'
    }}
  >
    {/* Column 1: Recipe Name & Author */}
    <div style={{ flex: '0 0 20%', display: 'flex', flexDirection: 'column', justifyContent: 'flex-start' }}>
      <div>
        <h4>{toTitleCase(dataObj.recipe_name)}</h4>
        <p style={{ fontSize: '0.85rem', color: '#666', margin: 0 }}>
          <strong>{dataObj.name}</strong><br />
          {dataObj.created_at}
        </p>
      </div>
    </div>

    {/* Column 2: Ingredients */}
    <div style={{ flex: '0 0 20%' }}>
      <h5 style={{ marginBottom: '0.5rem' }}>Ingredients</h5>
      <ul style={{ paddingLeft: '1.2rem', margin: 0, fontSize: '0.9rem' }}>
        {dataObj.ingredients.split(',').map((item, idx) => (
          <li key={idx}>{item.trim()}</li>
        ))}
      </ul>
    </div>

    {/* Column 3: Recipe Method */}
    <div style={{ flex: 1 }}>
      <h5 style={{ marginBottom: '0.5rem' }}>Recipe Method</h5>
      <div style={{ fontSize: '0.95rem', lineHeight: '1.5' }}>
        {dataObj.description}
      </div>
    </div>
  </div>

  {/* Optional HR */}
  {/* {index !== data.length - 1 && <hr className="thick-line" style={{ marginTop: '1.5rem' }} />} */}
</div>
      );
      })}
    </div>
  );
};
export default ContestRecipe;











