import React, { useState, useEffect } from "react";

const CountdownTimer = ({ days }) => {
  const savedTargetDate = localStorage.getItem("targetDate");
  const targetDate = savedTargetDate
    ? new Date(savedTargetDate)
    : new Date(new Date().getTime() + days * 24 * 60 * 60 * 1000);

  useEffect(() => {
    if (!savedTargetDate) {
      localStorage.setItem("targetDate", targetDate);
    }
  }, [targetDate, savedTargetDate]);

  const [timeLeft, setTimeLeft] = useState(calculateTimeLeft());

  function calculateTimeLeft() {
    const difference = targetDate - new Date();
    let timeLeft = {};

    if (difference > 0) {
      timeLeft = {
        days: Math.floor(difference / (1000 * 60 * 60 * 24)),
        hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
        minutes: Math.floor((difference / (1000 * 60)) % 60),
        seconds: Math.floor((difference / 1000) % 60),
      };
    } else {
      timeLeft = {
        days: 0,
        hours: 0,
        minutes: 0,
        seconds: 0,
      };
    }
    return timeLeft;
  }

  useEffect(() => {
    const timer = setInterval(() => {
      setTimeLeft(calculateTimeLeft());
    }, 1000);

    return () => clearInterval(timer);
  }, []);

  const timerComponents = Object.keys(timeLeft).map((interval) => (
    <div
      key={interval}
      style={{
        display: "inline-block",
        margin: "0 10px",
        textAlign: "center",
      }}
    >
      <div
        style={{
          backgroundColor: "#007bff",
          color: "white",
          padding: "15px",
          borderRadius: "5px",
          height: "80px",
          width: "80px",
          display: "flex",
          flexDirection: "column",
          justifyContent: "center",
          alignItems: "center",
          transition: "all 0.3s",
        }}
      >
        <div
          style={{
            fontSize: "1.5em",
            fontWeight: "bold",
            transition: "font-size 0.3s",
          }}
        >
          {timeLeft[interval]}
        </div>
        <div
          style={{
            fontSize: "12px",
            transition: "font-size 0.3s",
          }}
        >
          {interval.toUpperCase()}
        </div>
      </div>
    </div>
  ));

  return (
    <div
      style={{
        display: "flex",
        justifyContent: "center",
        flexWrap: "wrap",
        gap: "15px",
        padding: "10px",
        transition: "all 0.3s",
      }}
    >
      {timerComponents}
      <style>
        {`
          @media (max-width: 1024px) {
            div[style*="display: flex;"] {
              gap: 10px !important;
            }
            div[style*="inline-block"] div {
              height: 70px !important;
              width: 90px !important;
              padding: 10px !important;
            }
            div[style*="inline-block"] div > div:first-child {
              font-size: 1.2em !important;
            }
            div[style*="inline-block"] div > div:last-child {
              font-size: 0.9em !important;
            }
          }
          @media (max-width: 768px) {
            div[style*="display: flex;"] {
              gap: 8px !important;
            }
            div[style*="inline-block"] div {
              height: 60px !important;
              width: 80px !important;
              padding: 2px !important;
            }
            div[style*="inline-block"] div > div:first-child {
              font-size: 1em !important;
            }
            div[style*="inline-block"] div > div:last-child {
              font-size: 0.8em !important;
            }
          }
          @media (max-width: 480px) {
            div[style*="display: flex;"] {
              gap: 5px !important;
            }
            div[style*="inline-block"] div {
              height: 50px !important;
              width: 56px !important;
              padding: 0px !important;
            }
            div[style*="inline-block"] div > div:first-child {
              font-size: 0.9em !important;
            }
            div[style*="inline-block"] div > div:last-child {
              font-size: 0.7em !important;
            }
          }
        `}
      </style>
    </div>
  );
};

export default CountdownTimer;
