import React from 'react'
import "./css/newsletter.css"
export default function Newsletter() {
  return (
   
      


    
    
    

    <div className="newsletter-page" style={{ backgroundColor: '#E7FAFE' }}>

<center>
    <h1 style={{paddingTop: '2%'}}>Our Choices</h1>   
  </center>

   

    <div className="newsletter-card">
      
     
      {/* Left Image */}
      <img
        src="\img\cake.jpg" // Replace with your image path
        alt="Food items"
        className="bottom-image"
        style={{ borderRadius: '15px' }}
      />

      <img
        src="\img\coffee.jpg" // Replace with your image path
        alt="Food items"
        className="bottom-image"
        style={{ borderRadius: '15px' }}
      />

      {/* Right Image */}
      <img
        src="\img\salad.jpg" // Replace with your image path
        alt="Salad bowl"
        className="bottom-image"
        style={{ borderRadius: '15px' }}
      />
    </div>
  </div>
  
  )
}
